import { contextBridge, ipcRenderer } from 'electron';
import { Channels } from '../shared/channels';
import type {
  AppConfig,
  PreviewSelection,
  RecordingOptions,
  RecordingState,
  ScreenSource,
} from '../shared/types';

const toolbarAPI = {
  getScreens: (): Promise<ScreenSource[]> =>
    ipcRenderer.invoke(Channels.DEVICES_GET_SCREENS) as Promise<ScreenSource[]>,
  startRecording: (options: RecordingOptions): Promise<void> =>
    ipcRenderer.invoke(Channels.RECORDING_START, options) as Promise<void>,
  stopRecording: (): Promise<void> => ipcRenderer.invoke(Channels.RECORDING_STOP) as Promise<void>,
  pauseRecording: (): Promise<void> =>
    ipcRenderer.invoke(Channels.RECORDING_PAUSE) as Promise<void>,
  resumeRecording: (): Promise<void> =>
    ipcRenderer.invoke(Channels.RECORDING_RESUME) as Promise<void>,
  onStateUpdate: (callback: (state: RecordingState) => void): (() => void) => {
    const handler = (_event: Electron.IpcRendererEvent, state: RecordingState): void =>
      callback(state);
    ipcRenderer.on(Channels.TOOLBAR_STATE_UPDATE, handler);
    return (): void => {
      ipcRenderer.removeListener(Channels.TOOLBAR_STATE_UPDATE, handler);
    };
  },
  sendPreviewUpdate: (selection: PreviewSelection): void => {
    ipcRenderer.send(Channels.PREVIEW_UPDATE, selection);
  },
  openEditModal: (): Promise<void> => ipcRenderer.invoke(Channels.EDIT_MODAL_OPEN) as Promise<void>,
  getConfig: (): Promise<AppConfig> => ipcRenderer.invoke(Channels.CONFIG_GET),
  saveConfig: (partial: Partial<AppConfig>): void => {
    ipcRenderer.send(Channels.CONFIG_SAVE, partial);
  },
  checkForUpdate: (): Promise<{ available: boolean; version: string; url: string }> =>
    ipcRenderer.invoke(Channels.APP_CHECK_UPDATE),
  openUrl: (url: string): Promise<void> =>
    ipcRenderer.invoke(Channels.APP_OPEN_EXTERNAL, url) as Promise<void>,
  quitApp: (): void => {
    ipcRenderer.send(Channels.APP_QUIT);
  },
};

contextBridge.exposeInMainWorld('toolbarAPI', toolbarAPI);
